import{_ as e,c as i,a as s,o as p}from"./app-CEcM0piI.js";const n={};function h(l,a){return p(),i("div",null,a[0]||(a[0]=[s('<h2 id="电路交换" tabindex="-1"><a class="header-anchor" href="#电路交换"><span>电路交换</span></a></h2><p>优点：</p><ol><li>通信时延小</li><li>有序传输</li><li>没有冲突</li><li>适用范围广</li><li>实时性强</li><li>控制简单</li></ol><p>缺点：</p><ol><li>建立连接时间长</li><li>线路独占，使用效率低</li><li>灵活性差</li><li>难以规格化</li></ol><h2 id="报文交换" tabindex="-1"><a class="header-anchor" href="#报文交换"><span>报文交换</span></a></h2><p>优点：</p><ol><li>无需建立连接</li><li>动态分配线路</li><li>提高线路可靠性</li><li>提高线路利用率</li><li>提供多目标服务</li></ol><p>缺点：</p><ol><li>引起了转发时延</li><li>需要较大存储缓存空间</li><li>需要传输额外的信息量</li></ol><h2 id="分组交换" tabindex="-1"><a class="header-anchor" href="#分组交换"><span>分组交换</span></a></h2><p>优点：</p><ol><li>无需建立连接</li><li>线路利用率高</li><li>简化了存储管理</li><li>加速传输</li><li>减少出错概率和重发数据量</li></ol><p>缺点：</p><ol><li>引起了转发时延</li><li>需要传输额外的信息量</li><li>对于数据报服务，存午失序、丢失或重气分绍的问题:对于虚电路服务，存在呼叫建立、数据传输和虚电路释放三个过程</li></ol><h1 id="计算机网络的分类" tabindex="-1"><a class="header-anchor" href="#计算机网络的分类"><span>计算机网络的分类</span></a></h1><h2 id="按交换技术分类" tabindex="-1"><a class="header-anchor" href="#按交换技术分类"><span>按交换技术分类</span></a></h2><p>电路交换网络 报文交换网络 分组交换网络</p><h2 id="按覆盖范围分类" tabindex="-1"><a class="header-anchor" href="#按覆盖范围分类"><span>按覆盖范围分类</span></a></h2><p>广域网WAN 城域网MAN 局域网LAN 个域网PAN</p><h2 id="按使用者分类" tabindex="-1"><a class="header-anchor" href="#按使用者分类"><span>按使用者分类</span></a></h2><p>公用网 专用网</p><h2 id="按传输介质分类" tabindex="-1"><a class="header-anchor" href="#按传输介质分类"><span>按传输介质分类</span></a></h2><p>有线网络 无线网络</p><h2 id="按拓扑结构分类" tabindex="-1"><a class="header-anchor" href="#按拓扑结构分类"><span>按拓扑结构分类</span></a></h2><p>总线型网络 星型网络 环型网络 网状型网络</p><h1 id="性能指标" tabindex="-1"><a class="header-anchor" href="#性能指标"><span>性能指标</span></a></h1><h2 id="速率" tabindex="-1"><a class="header-anchor" href="#速率"><span>速率</span></a></h2><h3 id="比特" tabindex="-1"><a class="header-anchor" href="#比特"><span>比特</span></a></h3><p>计算机中数据量的单位，也是信息论中信息量的单位。一个比特就是二进制数字中的一个1或0 Byte：字节，常用大写字母B表示 bit：比特，常用小写字母b表示</p><p>1Byte=8bit 1KB=2^10B 1MB=2^10KB 1GB=2^10MB 1TB=2^10GB</p><h3 id="速率-1" tabindex="-1"><a class="header-anchor" href="#速率-1"><span>速率</span></a></h3><p>连接在计算机网络上的主机在数字信道上传送比特的速率，也称为比特率或数据率 常用数据率单位： bit/s(b/s, bps) 1kb/s = 10^3b/s(bps) 1Mb/s=10^3kb/s(kbps) 1Gb/s =10^3Mb/s(Mbps) 1Tb/s =10^3Gb/s(Gbps)</p><h2 id="带宽" tabindex="-1"><a class="header-anchor" href="#带宽"><span>带宽</span></a></h2><p>带宽在模拟信号系统中的意义： 信号所包含的各种不同频率成分所占据的频率范围： 单位：Hz(kHz，MHz，GHz)</p><p>带宽在计算机网络中的意义： 用来表示网络的通信线路所能传送数据的能力，因此网络带宽表示在单位时间内从网络中的某一点到另一点所能通过的“最高数据率”. 单位：b/s(kb/s，Mb/s，Gb/s，Tb/s)</p><h2 id="吞吐量" tabindex="-1"><a class="header-anchor" href="#吞吐量"><span>吞吐量</span></a></h2><p>吞吐量表示在单位时间内通过某个网络(或信道、接口)的数据量 吞吐量被经常用于对现实世界中的网络的一种测量，以便知道实际上到底有多少数据量能够通过网络。 吞吐量受网络的带宽或额定速率的限制</p><h2 id="时延" tabindex="-1"><a class="header-anchor" href="#时延"><span>时延</span></a></h2><p>源主机将分组发往传输线路需要花费的时间称为发送时延 发送时延=分组长度/发送速率</p><p>代表分组的电信号在链路上传输花费的时间称为传播时延 传播时延=信道长度/传播速率</p><p>路由器收到分组后对其存储转发花费的时间称为处理时延 一般不方便计算</p><h2 id="时延带宽积" tabindex="-1"><a class="header-anchor" href="#时延带宽积"><span>时延带宽积</span></a></h2><p>时延带宽积=传播时延* 带宽</p><h2 id="往返时间" tabindex="-1"><a class="header-anchor" href="#往返时间"><span>往返时间</span></a></h2><p>在许多情况下，因特网上的信息不仅仅单方向传输，而是双向交互 我们有时很需要知道双向交互一次所需的时间 因此，往返时间RTT(Round-Trip Time)也是一个重要的性能指标。</p><p>从源主机发送分组开始直到源主机收到来自目的主机的确认分组为止所需要的时间</p><h2 id="利用率" tabindex="-1"><a class="header-anchor" href="#利用率"><span>利用率</span></a></h2><p>信道利用率 用来表示某信道有百分之几的时间是被利用的(有数据通过)</p><p>网络利用率 全网络的信道利用率的加权平均 根据排队论，当某信道的利用率增大时，该信道引起的时延也会迅速增加; 因此，信道利用率并非越高越好 如果令Do表示网络空闲时的时延，D表示网络当前的时延，那么在适当的假定条件下，可以用下面的简单公式来表示D、Do和利用率U之间的关系 D=D_0/(1-u) ![[Pasted image 20240306211259.png]] 当网络的利用率达到50%时，时延就要加倍; 时延急剧增大;当网络的利用率超过50%时， 当网络的利用率接近100%时，时延就趋于无穷大; 因此，一些拥有较大主干网的ISP通常会控制它们的信道利用率不超过50%。如果超过了，就要准备扩容，增大线路的带宽。</p><p>也不能使信道利用率太低，这会使宝贵的通信资源被白白浪费。应该使用一些机制，可以根据情况动态调整输入到网络中的通信量，使网络利用率保持在一个合理的范围内。</p><h2 id="丢包率" tabindex="-1"><a class="header-anchor" href="#丢包率"><span>丢包率</span></a></h2><p>丢包率即分组丢失率，是指在一定的时间范围内，传输过程中丢失的分组数量与总分组数量的比率丢包率具体可分为接口丢包率、结点丢包率、链路丢包率、路径丢包率、网络丢包率等 丢包率是网络运维人员非常关心的一个网络性能指标，但对于普通用户来说往往并不关心这个指标因为他们通常意识不到网络丢包。</p><p>分组丢失主要有两种情况: 分组在传输过程中出现误码，被结点丢弃， 分组到达一台队列已满的分组交换机时被丢弃;在通信量较大时就可能造成网络拥塞。 因此，丢包率反映了网络的拥塞情况:</p><p>无拥塞时路径丢包率为0 轻度拥塞时路径丢包率为1%~4% 严重拥塞时路径手包率为5%~15%</p>',55)]))}const d=e(n,[["render",h]]),t=JSON.parse('{"path":"/base/cn/1/","title":"1、组成","lang":"zh-CN","frontmatter":{"title":"1、组成","createTime":"2025/06/18 20:42:40","permalink":"/base/cn/1/"},"readingTime":{"minutes":5.2,"words":1561},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/计算机网络/1、组成.md","headers":[]}');export{d as comp,t as data};
